"""Smart AI router: inference pool, routing strategies, health management."""

from __future__ import annotations

import asyncio
import logging
import random
import time
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

from . import BaseDriver, DriverHealth, DriverMetrics, InferenceRequest, InferenceResponse

logger = logging.getLogger("aether.ai.router")


class RoutingStrategy(str, Enum):
    ROUND_ROBIN = "round_robin"
    LEAST_LATENCY = "least_latency"
    LEAST_LOADED = "least_loaded"
    COST_OPTIMIZED = "cost_optimized"
    PRIORITY = "priority"
    RANDOM = "random"


class HealthStatus(str, Enum):
    HEALTHY = "healthy"
    DEGRADED = "degraded"
    UNHEALTHY = "unhealthy"


@dataclass
class DriverEntry:
    """Wrapper around a driver with routing metadata."""
    driver: BaseDriver
    priority: int = 0
    cost_per_1k_tokens: float = 0.0
    max_concurrent: int = 10
    _current_requests: int = 0
    _consecutive_failures: int = 0
    _last_health: Optional[DriverHealth] = None
    _last_health_at: float = 0.0

    @property
    def is_healthy(self) -> bool:
        if self._consecutive_failures >= 3:
            return False
        if self._last_health and self._last_health.status == "error":
            return False
        return True

    @property
    def current_load(self) -> float:
        return self._current_requests / max(self.max_concurrent, 1)

    def mark_request_start(self):
        self._current_requests += 1

    def mark_request_done(self, success: bool):
        self._current_requests = max(0, self._current_requests - 1)
        if success:
            self._consecutive_failures = 0
        else:
            self._consecutive_failures += 1


class InferencePool:
    """Pool of AI drivers with smart routing."""

    def __init__(self, health_check_interval: float = 30.0):
        self._drivers: dict[str, DriverEntry] = {}
        self._health_check_interval = health_check_interval
        self._health_task: Optional[asyncio.Task] = None
        self._round_robin_idx = 0
        self._lock = asyncio.Lock()

    def register(
        self,
        driver: BaseDriver,
        priority: int = 0,
        cost_per_1k: float = 0.0,
        max_concurrent: int = 10,
    ):
